-- =============================================================================
-- PharmaLabel Designer — Local PostgreSQL Setup Script
-- =============================================================================
-- Generated by: Antigravity (mirrored from Supabase project: LABEL DESIGNER)
-- PostgreSQL Version: 17+
-- Run as: psql -U postgres -d pharmalabel -f local_postgres_setup.sql
--
-- USAGE:
--   1. Create the database first:
--        createdb -U postgres pharmalabel
--   2. Then run this script:
--        psql -U postgres -d pharmalabel -f local_postgres_setup.sql
-- =============================================================================

-- ── 0.  Setup Schemas and Extensions ──────────────────────────────────────────
CREATE SCHEMA IF NOT EXISTS extensions;

-- Enable required extensions in extensions schema
CREATE EXTENSION IF NOT EXISTS "uuid-ossp" SCHEMA extensions;
CREATE EXTENSION IF NOT EXISTS "pgcrypto" SCHEMA extensions;

-- Add extensions to search path for easier usage
ALTER DATABASE pharmalabel SET search_path TO "$user", public, extensions;

-- =============================================================================
-- SECTION 1: ENUMS
-- =============================================================================

DO $$ BEGIN
  CREATE TYPE public.signature_meaning AS ENUM (
    'APPROVED_FOR_RELEASE',
    'REVIEW_COMPLETE',
    'REJECTED',
    'MARKED_COMPLETE'
  );
EXCEPTION
  WHEN duplicate_object THEN NULL;
END $$;


-- =============================================================================
-- SECTION 2: TABLE DEFINITIONS
-- (Order respects foreign key dependencies)
-- =============================================================================

-- ── 2.1  roles ────────────────────────────────────────────────────────────────
CREATE TABLE IF NOT EXISTS public.roles (
  id         UUID        PRIMARY KEY DEFAULT extensions.gen_random_uuid(),
  name       TEXT        NOT NULL UNIQUE,
  created_at TIMESTAMPTZ DEFAULT timezone('utc'::text, now())
);

-- ── 2.2  users ────────────────────────────────────────────────────────────────
CREATE TABLE IF NOT EXISTS public.users (
  id                    UUID        PRIMARY KEY DEFAULT extensions.gen_random_uuid(),
  username              TEXT        NOT NULL UNIQUE,
  email                 TEXT        NOT NULL UNIQUE,
  password_hash         TEXT        NOT NULL,
  role_id               UUID        CONSTRAINT users_role_id_fkey REFERENCES public.roles(id),
  status                TEXT        DEFAULT 'ACTIVE'::text,
  token_version         INTEGER     DEFAULT 0,
  failed_login_attempts INTEGER     DEFAULT 0,
  locked_until          TIMESTAMPTZ,
  password_changed_at   TIMESTAMPTZ DEFAULT timezone('utc'::text, now()),
  must_change_password  BOOLEAN     DEFAULT true,
  created_at            TIMESTAMPTZ DEFAULT timezone('utc'::text, now()),
  is_external           BOOLEAN     DEFAULT false,
  deleted_at            TIMESTAMPTZ
);

-- ── 2.3  permissions ──────────────────────────────────────────────────────────
CREATE TABLE IF NOT EXISTS public.permissions (
  id      UUID    PRIMARY KEY DEFAULT extensions.gen_random_uuid(),
  role_id UUID    CONSTRAINT permissions_role_id_fkey REFERENCES public.roles(id),
  module  TEXT    NOT NULL,
  event   TEXT    NOT NULL,
  allowed BOOLEAN DEFAULT false,
  user_id UUID    CONSTRAINT permissions_user_id_fkey REFERENCES public.users(id)
);

-- ── 2.4  user_auth_tokens ─────────────────────────────────────────────────────
CREATE TABLE IF NOT EXISTS public.user_auth_tokens (
  id         UUID        PRIMARY KEY DEFAULT extensions.gen_random_uuid(),
  user_id    UUID        CONSTRAINT user_auth_tokens_user_id_fkey REFERENCES public.users(id),
  token_hash TEXT        NOT NULL,
  family_id  UUID        NOT NULL,
  revoked    BOOLEAN     DEFAULT false,
  expires_at TIMESTAMPTZ NOT NULL,
  created_at TIMESTAMPTZ DEFAULT timezone('utc'::text, now())
);

-- ── 2.5  audit_logs ───────────────────────────────────────────────────────────
CREATE TABLE IF NOT EXISTS public.audit_logs (
  id        UUID        PRIMARY KEY DEFAULT extensions.gen_random_uuid(),
  user_id   UUID        CONSTRAINT audit_logs_user_id_fkey REFERENCES public.users(id),
  action    TEXT        NOT NULL,
  module    TEXT        NOT NULL,
  event     TEXT        NOT NULL,
  old_data  JSONB,
  new_data  JSONB,
  timestamp TIMESTAMPTZ DEFAULT timezone('utc'::text, now())
);

-- ── 2.6  electronic_signatures ────────────────────────────────────────────────
CREATE TABLE IF NOT EXISTS public.electronic_signatures (
  id         UUID              PRIMARY KEY DEFAULT extensions.gen_random_uuid(),
  user_id    UUID              CONSTRAINT electronic_signatures_user_id_fkey REFERENCES public.users(id),
  target_id  UUID              NOT NULL,
  version_id UUID,
  meaning    public.signature_meaning NOT NULL,
  reason     TEXT,
  signed_at  TIMESTAMPTZ       DEFAULT timezone('utc'::text, now()),
  ip_address TEXT
);

-- ── 2.7  templates (system predefined templates) ──────────────────────────────
CREATE TABLE IF NOT EXISTS public.templates (
  id            UUID        PRIMARY KEY DEFAULT extensions.gen_random_uuid(),
  name          TEXT        NOT NULL,
  brand         TEXT        NOT NULL,
  category      TEXT        NOT NULL,
  size          TEXT        NOT NULL,
  image_url     TEXT,
  elements_data JSONB       NOT NULL DEFAULT '[]'::jsonb,
  created_at    TIMESTAMPTZ DEFAULT timezone('utc'::text, now()),
  updated_at    TIMESTAMPTZ DEFAULT timezone('utc'::text, now()),
  user_id       TEXT        DEFAULT 'SYSTEM'::text
);

-- ── 2.8  saved_templates (user-created labels) ────────────────────────────────
CREATE TABLE IF NOT EXISTS public.saved_templates (
  id           UUID        PRIMARY KEY DEFAULT extensions.uuid_generate_v4(),
  user_id      TEXT        NOT NULL,
  name         TEXT        NOT NULL,
  label_size   JSONB,
  bg_color     TEXT,
  elements_data JSONB,
  created_at   TIMESTAMPTZ DEFAULT now(),
  updated_at   TIMESTAMPTZ DEFAULT now(),
  completed_by UUID        CONSTRAINT saved_templates_completed_by_fkey REFERENCES public.users(id),
  approved_by  UUID        CONSTRAINT saved_templates_approved_by_fkey REFERENCES public.users(id),
  owner_uuid   UUID        CONSTRAINT saved_templates_owner_uuid_fkey REFERENCES public.users(id)
);

-- ── 2.9  template_versions (audit trail of label edits) ───────────────────────
CREATE TABLE IF NOT EXISTS public.template_versions (
  id                UUID        PRIMARY KEY DEFAULT extensions.gen_random_uuid(),
  template_id       UUID        CONSTRAINT template_versions_template_id_fkey REFERENCES public.templates(id),
  version_number    INTEGER     NOT NULL,
  elements_data     JSONB       NOT NULL DEFAULT '[]'::jsonb,
  created_at        TIMESTAMPTZ DEFAULT timezone('utc'::text, now()),
  saved_template_id UUID        CONSTRAINT template_versions_saved_template_id_fkey REFERENCES public.saved_templates(id)
);

-- ── 2.10  user_sessions ───────────────────────────────────────────────────────
CREATE TABLE IF NOT EXISTS public.user_sessions (
  id                    UUID        PRIMARY KEY DEFAULT extensions.gen_random_uuid(),
  user_id               TEXT        NOT NULL UNIQUE,
  dashboard_preferences JSONB       DEFAULT '{}'::jsonb,
  recent_activity_log   JSONB       DEFAULT '[]'::jsonb,
  last_accessed         TIMESTAMPTZ DEFAULT timezone('utc'::text, now())
);

-- ── 2.11  user_labels (draft/scratch labels per user) ─────────────────────────
CREATE TABLE IF NOT EXISTS public.user_labels (
  id            UUID        PRIMARY KEY DEFAULT extensions.gen_random_uuid(),
  user_id       TEXT        NOT NULL,
  name          TEXT        NOT NULL,
  size          TEXT,
  bg_color      TEXT,
  elements_data JSONB,
  created_at    TIMESTAMPTZ DEFAULT timezone('utc'::text, now()),
  updated_at    TIMESTAMPTZ DEFAULT timezone('utc'::text, now())
);

-- ── 2.12  system_config ───────────────────────────────────────────────────────
CREATE TABLE IF NOT EXISTS public.system_config (
  id           UUID        PRIMARY KEY DEFAULT extensions.gen_random_uuid(),
  config_key   TEXT        NOT NULL UNIQUE,
  config_value TEXT        NOT NULL,
  description  TEXT,
  updated_at   TIMESTAMPTZ DEFAULT timezone('utc'::text, now())
);


-- =============================================================================
-- SECTION 3: INDEXES (performance)
-- =============================================================================

CREATE INDEX IF NOT EXISTS idx_permissions_role_id     ON public.permissions(role_id);
CREATE INDEX IF NOT EXISTS idx_permissions_user_id     ON public.permissions(user_id);
CREATE INDEX IF NOT EXISTS idx_auth_tokens_user_id     ON public.user_auth_tokens(user_id);
CREATE INDEX IF NOT EXISTS idx_auth_tokens_family_id   ON public.user_auth_tokens(family_id);
CREATE INDEX IF NOT EXISTS idx_audit_logs_user_id      ON public.audit_logs(user_id);
CREATE INDEX IF NOT EXISTS idx_audit_logs_timestamp    ON public.audit_logs("timestamp");
CREATE INDEX IF NOT EXISTS idx_templates_category      ON public.templates(category);
CREATE INDEX IF NOT EXISTS idx_saved_templates_user_id ON public.saved_templates(user_id);
CREATE INDEX IF NOT EXISTS idx_template_versions_tid   ON public.template_versions(template_id);
CREATE INDEX IF NOT EXISTS idx_user_labels_user_id     ON public.user_labels(user_id);
CREATE INDEX IF NOT EXISTS idx_users_role_id           ON public.users(role_id);


